1	import { useCallback, useEffect, useRef, useState } from 'react';
2	import { BrowserMultiFormatReader } from '@zxing/browser';
3	import { BarcodeFormat, DecodeHintType } from '@zxing/library';
4	import { isDuplicate, formatToString } from './scannerHelpers';
5	import type {
6	  CameraDevice,
7	  NormalizedScanResult,
8	  ScannerStatus,
9	} from '../types/scanner';
10	
11	const SUPPORTED_FORMATS: BarcodeFormat[] = [
12	  BarcodeFormat.QR_CODE, BarcodeFormat.UPC_A, BarcodeFormat.UPC_E,
13	  BarcodeFormat.EAN_13, BarcodeFormat.EAN_8,
14	  BarcodeFormat.CODE_128, BarcodeFormat.CODE_39,
15	];
16	
17	const DECODE_HINTS = new Map<DecodeHintType, unknown>();
18	DECODE_HINTS.set(DecodeHintType.POSSIBLE_FORMATS, SUPPORTED_FORMATS);
19	
20	export type ScannerErrorKind =
21	  | 'permission-denied' | 'no-camera' | 'camera-in-use'
22	  | 'decode-error' | 'insecure-context' | 'unknown';
23	
24	export interface ScannerError { kind: ScannerErrorKind; message: string; }
25	
26	interface ZxingResult {
27	  getText(): string;
28	  getBarcodeFormat(): BarcodeFormat;
29	}
30	
31	export interface BarcodeScannerOptions {
32	  cooldownMs?: number;
33	  onScan: (r: NormalizedScanResult) => void;
34	  paused?: boolean;
35	}
36	
37	export interface BarcodeScannerResult {
38	  status: ScannerStatus;
39	  error: ScannerError | null;
40	  devices: CameraDevice[];
41	  selectedDeviceId: string | null;
42	  torchSupported: boolean;
43	  torchOn: boolean;
44	  lastResult: NormalizedScanResult | null;
45	  start: () => Promise<void>;
46	  stop: () => void;
47	  switchDevice: (deviceId: string) => Promise<void>;
48	  toggleTorch: () => Promise<void>;
49	  pause: () => void;
50	  resume: () => void;
51	}
52	export function useBarcodeScanner(options: BarcodeScannerOptions): BarcodeScannerResult {
53	  const { cooldownMs = 2000, onScan, paused = false } = options;
54	
55	  const [status, setStatus] = useState<ScannerStatus>('idle');
56	  const [error, setError] = useState<ScannerError | null>(null);
57	  const [devices, setDevices] = useState<CameraDevice[]>([]);
58	  const [selectedDeviceId, setSelectedDeviceId] = useState<string | null>(null);
59	  const [torchSupported, setTorchSupported] = useState(false);
60	  const [torchOn, setTorchOn] = useState(false);
61	  const [lastResult, setLastResult] = useState<NormalizedScanResult | null>(null);
62	
63	  const controlsRef = useRef<{ stop: () => void } | null>(null);
64	  const videoElRef = useRef<HTMLVideoElement | null>(null);
65	  const prevCodeRef = useRef<string | null>(null);
66	  const prevAtMsRef = useRef<number>(0);
67	  const pausedRef = useRef(paused);
68	
69	  useEffect(() => { pausedRef.current = paused; }, [paused]);
70	
71	  const stopTracks = useCallback(() => {
72	    const videoEl = videoElRef.current;
73	    if (videoEl?.srcObject) {
74	      const stream = videoEl.srcObject as MediaStream;
75	      stream.getTracks().forEach((track) => track.stop());
76	      videoEl.srcObject = null;
77	    }
78	  }, []);
79	
80	  const stop = useCallback(() => {
81	    if (controlsRef.current) { controlsRef.current.stop(); controlsRef.current = null; }
82	    stopTracks();
83	    setStatus('idle');
84	    setTorchOn(false);
85	  }, [stopTracks]);
86	
87	  const handleResult = useCallback(
88	    (result: ZxingResult) => {
89	      if (pausedRef.current) return;
90	      const now = Date.now();
91	      const code = result.getText();
92	      if (isDuplicate(prevCodeRef.current, prevAtMsRef.current, code, now, cooldownMs)) return;
93	      prevCodeRef.current = code;
94	      prevAtMsRef.current = now;
95	      const normalized: NormalizedScanResult = {
96	        code,
97	        format: formatToString(result.getBarcodeFormat()),
98	        source: 'mobile-camera',
99	        scannedAtUtc: new Date(now).toISOString(),
100	      };
101	      setLastResult(normalized);
102	      onScan(normalized);
103	    },
104	    [cooldownMs, onScan]
105	  );
106	  const ignoreDecodeErr = (err: unknown) => {
107	    const n = (err as Error).name;
108	    if (n !== 'NotFoundException' && n !== 'ChecksumException' && n !== 'FormatException') {
109	      console.error('Decode error:', err);
110	    }
111	  };
112	
113	  const start = useCallback(async () => {
114	    if (!window.isSecureContext) {
115	      setStatus('error');
116	      setError({ kind: 'insecure-context', message: 'Camera access requires a secure context (HTTPS or localhost).' });
117	      return;
118	    }
119	    setStatus('requesting-permission');
120	    setError(null);
121	    try {
122	      const reader = new BrowserMultiFormatReader(DECODE_HINTS);
123	      const videoDevices = await BrowserMultiFormatReader.listVideoInputDevices();
124	      const cameraDevices: CameraDevice[] = videoDevices.map((d) => ({
125	        deviceId: d.deviceId,
126	        label: d.label || ('Camera ' + d.deviceId.slice(0, 8)),
127	      }));
128	      setDevices(cameraDevices);
129	      const videoEl = document.createElement('video');
130	      videoEl.setAttribute('playsinline', 'true');
131	      videoElRef.current = videoEl;
132	      const constraints: MediaStreamConstraints = { video: { facingMode: 'environment' }, audio: false };
133	      const controls = await reader.decodeFromConstraints(constraints, videoEl, (result, err) => {
134	        if (result) handleResult(result as unknown as ZxingResult);
135	        if (err) ignoreDecodeErr(err);
136	      });
137	      controlsRef.current = controls;
138	      setStatus('active');
139	      if (cameraDevices.length > 0) setSelectedDeviceId(cameraDevices[0].deviceId);
140	      const stream = videoEl.srcObject as MediaStream | null;
141	      if (stream) {
142	        const track = stream.getVideoTracks()[0];
143	        if (track) {
144	          const caps = track.getCapabilities?.() as (MediaTrackCapabilities & { torch?: boolean }) | undefined;
145	          setTorchSupported(!!caps?.torch);
146	        }
147	      }
148	    } catch (err) {
149	      const e = err as Error;
150	      let kind: ScannerErrorKind = 'unknown';
151	      if (e.name === 'NotAllowedError' || e.name === 'PermissionDeniedError') kind = 'permission-denied';
152	      else if (e.name === 'NotFoundError' || e.name === 'DevicesNotFoundError') kind = 'no-camera';
153	      else if (e.name === 'NotReadableError' || e.name === 'TrackStartError') kind = 'camera-in-use';
154	      setStatus('error');
155	      setError({ kind, message: e.message });
156	    }
157	  }, [handleResult]);
158	  const switchDevice = useCallback(
159	    async (deviceId: string) => {
160	      stop();
161	      setSelectedDeviceId(deviceId);
162	      const reader = new BrowserMultiFormatReader(DECODE_HINTS);
163	      const videoEl = document.createElement('video');
164	      videoEl.setAttribute('playsinline', 'true');
165	      videoElRef.current = videoEl;
166	      try {
167	        const devControls = await reader.decodeFromVideoDevice(deviceId, videoEl, (result, err) => {
168	          if (result) handleResult(result as unknown as ZxingResult);
169	          if (err) ignoreDecodeErr(err);
170	        });
171	        controlsRef.current = devControls;
172	        setStatus('active');
173	      } catch (err) {
174	        const e = err as Error;
175	        setStatus('error');
176	        setError({ kind: 'unknown', message: e.message });
177	      }
178	    },
179	    [handleResult, stop]
180	  );
181	
182	  const toggleTorch = useCallback(async () => {
183	    const videoEl = videoElRef.current;
184	    if (!videoEl?.srcObject) return;
185	    const stream = videoEl.srcObject as MediaStream;
186	    const track = stream.getVideoTracks()[0];
187	    if (!track) return;
188	    try {
189	      const newTorchState = !torchOn;
190	      await track.applyConstraints({ advanced: [{ torch: newTorchState } as MediaTrackConstraintSet] });
191	      setTorchOn(newTorchState);
192	    } catch { /* Torch not supported */ }
193	  }, [torchOn]);
194	
195	  const pause = useCallback(() => { pausedRef.current = true; setStatus('paused'); }, []);
196	  const resume = useCallback(() => { pausedRef.current = false; setStatus('active'); }, []);
197	
198	  useEffect(() => {
199	    const handleVisibilityChange = () => {
200	      if (document.visibilityState === 'hidden') stopTracks();
201	    };
202	    document.addEventListener('visibilitychange', handleVisibilityChange);
203	    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
204	  }, [stopTracks]);
205	
206	  useEffect(() => {
207	    return () => {
208	      if (controlsRef.current) { controlsRef.current.stop(); controlsRef.current = null; }
209	      stopTracks();
210	    };
211	  }, [stopTracks]);
212	
213	  return { status, error, devices, selectedDeviceId, torchSupported, torchOn, lastResult, start, stop, switchDevice, toggleTorch, pause, resume };
214	}
