const BASE = process.env.BASE_URL ?? 'http://localhost:3000';
const USER = process.env.SMOKE_USER ?? 'admin';
const PASS = process.env.SMOKE_PASS ?? 'changeme';

test('login + dashboard + connect-mobile + mobile drawer + scanner-demo', async ({ page }) => {
  page.on('console', (m) => {
    if (m.type() === 'error') console.log('[console.error]', m.text());
  });
  page.on('pageerror', (e) => console.log('[pageerror]', e.message));

  // 1. Login
  await page.goto(`${BASE}/login`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-1-login.png', fullPage: true });

  // Find username/password fields by label text or input type
  const userInput = page.locator('input[type="text"], input[name="username"], input[autocomplete="username"]').first();
  const passInput = page.locator('input[type="password"]').first();
  await userInput.fill(USER);
  await passInput.fill(PASS);

  // Wait for the login network response, then for navigation off /login.
  const loginResp = page.waitForResponse(
    (r) => r.url().includes('/auth/login') && r.request().method() === 'POST',
    { timeout: 15_000 }
  );
  const submit = page.locator('button[type="submit"], button:has-text("Sign in"), button:has-text("Log in"), button:has-text("Login")').first();
  await submit.click();
  const resp = await loginResp;
  console.log('[login response]', resp.status(), await resp.text().catch(() => '<no body>'));

  // Wait for the SPA to navigate away from /login (200ms grace + URL check).
  await page.waitForFunction(() => !location.pathname.startsWith('/login'), null, { timeout: 10_000 }).catch(() => {});
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-2-after-login.png', fullPage: true });

  // 2. Should not be on /login anymore
  expect(page.url()).not.toContain('/login');

  // 3. Connect-mobile page renders QR
  await page.goto(`${BASE}/connect-mobile`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-3-connect-mobile.png', fullPage: true });
  await expect(page.getByRole('heading', { name: 'Pair a phone with this app' })).toBeVisible();
  await expect(page.locator('img[alt^="QR code for"]')).toBeVisible();

  // 4. Mobile experience entry
  await page.goto(`${BASE}/mobile`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-4-mobile-home.png', fullPage: true });

  // 5. Mobile lookup
  await page.goto(`${BASE}/mobile/lookup`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-5-mobile-lookup.png', fullPage: true });

  // 6. Mobile pickup
  await page.goto(`${BASE}/mobile/pickup`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-6-mobile-pickup.png', fullPage: true });

  // 7. Mobile scanner demo
  await page.goto(`${BASE}/mobile/scanner-demo`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-7-scanner-demo.png', fullPage: true });

  console.log('[smoke] all routes navigated, screenshots in .smoke/');
});

