import { test, expect } from '@playwright/test';

const BASE = process.env.BASE_URL ?? 'http://localhost:3000';
const USER = process.env.SMOKE_USER ?? 'admin';
const PASS = process.env.SMOKE_PASS ?? 'changeme';

test('login + dashboard + connect-mobile + mobile drawer + scanner-demo', async ({ page }) => {
  page.on('console', (m) => {
    if (m.type() === 'error') console.log('[console.error]', m.text());
  });
  page.on('pageerror', (e) => console.log('[pageerror]', e.message));
  page.on('response', (r) => {
    if (r.status() >= 400) console.log('[http]', r.status(), r.request().method(), r.url());
  });

  // 1. Login
  await page.goto(`${BASE}/login`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-1-login.png', fullPage: true });

  // Find username/password fields by label text or input type
  const userInput = page.locator('input[type="text"], input[name="username"], input[autocomplete="username"]').first();
  const passInput = page.locator('input[type="password"]').first();
  await userInput.fill(USER);
  await passInput.fill(PASS);

  // Wait for the login network response, then for navigation off /login.
  const loginResp = page.waitForResponse(
    (r) => r.url().includes('/auth/login') && r.request().method() === 'POST',
    { timeout: 15_000 }
  );
  const submit = page.locator('button[type="submit"], button:has-text("Sign in"), button:has-text("Log in"), button:has-text("Login")').first();
  await submit.click();
  const resp = await loginResp;
  console.log('[login response]', resp.status(), await resp.text().catch(() => '<no body>'));

  // Wait for the SPA to navigate away from /login (200ms grace + URL check).
  await page.waitForFunction(() => !location.pathname.startsWith('/login'), null, { timeout: 10_000 }).catch(() => {});
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-2-after-login.png', fullPage: true });

  // 2. Should not be on /login anymore
  expect(page.url()).not.toContain('/login');

  // 2b. Dashboard rendering — check for visible "unauthorized" banner
  await page.goto(`${BASE}/`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-2b-dashboard.png', fullPage: true });
  const bodyText = await page.locator('body').innerText();
  console.log('[dashboard body excerpt]', bodyText.slice(0, 400).replace(/\s+/g, ' '));
  if (bodyText.toLowerCase().includes('unauthorized')) {
    console.log('[!!] Dashboard shows "unauthorized" — capturing network requests');
  }

  // 3. Connect-mobile page renders QR
  await page.goto(`${BASE}/connect-mobile`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-3-connect-mobile.png', fullPage: true });
  await expect(page.getByRole('heading', { name: 'Pair a phone with this app' })).toBeVisible();
  await expect(page.locator('img[alt^="QR code for"]')).toBeVisible();

  // 4. Mobile experience entry
  await page.goto(`${BASE}/mobile`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-4-mobile-home.png', fullPage: true });

  // 5. Mobile lookup
  await page.goto(`${BASE}/mobile/lookup`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-5-mobile-lookup.png', fullPage: true });

  // 6. Mobile pickup
  await page.goto(`${BASE}/mobile/pickup`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-6-mobile-pickup.png', fullPage: true });

  // 7. Mobile scanner demo
  await page.goto(`${BASE}/mobile/scanner-demo`);
  await page.waitForLoadState('networkidle');
  await page.screenshot({ path: 'sc-7-scanner-demo.png', fullPage: true });

  console.log('[smoke] all routes navigated, screenshots in .smoke/');
});

import { useNavigate } from 'react-router-dom';
import { useAuthStore } from '@/stores/authStore.js';

export function MobileAccountPage() {
  const navigate = useNavigate();
  const currentUser = useAuthStore((s) => s.currentUser);
  const logout = useAuthStore((s) => s.logout);

  const handleLogout = async () => {
    await logout();
    navigate('/login', { replace: true });
  };

  if (!currentUser) {
    return (
      <div className="mobile-page-bg p-4">
        <p className="text-sm text-hawk-700">Not signed in.</p>
      </div>
    );
  }

  return (
    <div className="mobile-page-bg space-y-4 p-4 pb-24">
      <header className="space-y-1">
        <p className="mobile-type-eyebrow text-gold-700">Account</p>
        <h1 className="font-display text-2xl font-semibold tracking-tight text-hawk-800">
          {currentUser.username}
        </h1>
      </header>

      <section className="joy-shadow-plum rounded-2xl border border-gold-200 bg-[color:var(--joy-paper)] p-4">
        <dl className="space-y-3">
          <div>
            <dt className="text-[11px] font-bold uppercase tracking-[0.22em] text-hawk-600">
              Username
            </dt>
            <dd className="mt-1 font-mono text-sm text-hawk-900">
              {currentUser.username}
            </dd>
          </div>

          <div>
            <dt className="text-[11px] font-bold uppercase tracking-[0.22em] text-hawk-600">
              Roles
            </dt>
            <dd className="mt-1 flex flex-wrap gap-1.5">
              {currentUser.roles.length === 0 ? (
                <span className="text-sm italic text-hawk-600">No roles assigned</span>
              ) : (
                currentUser.roles.map((role) => (
                  <span
                    key={role}
                    className="rounded-full border border-gold-300 bg-gold-50 px-2.5 py-0.5 text-[11px] font-bold uppercase tracking-[0.18em] text-hawk-800"
                  >
                    {role}
                  </span>
                ))
              )}
            </dd>
          </div>

          <div>
            <dt className="text-[11px] font-bold uppercase tracking-[0.22em] text-hawk-600">
              Status
            </dt>
            <dd className="mt-1 text-sm text-hawk-900">
              {currentUser.isActive === false ? (
                <span className="text-red-700">Inactive</span>
              ) : (
                <span className="text-emerald-700">Active</span>
              )}
            </dd>
          </div>
        </dl>
      </section>

      <section className="space-y-2 rounded-2xl border border-hawk-200 bg-white/70 p-4">
        <h2 className="font-display text-lg font-semibold text-hawk-800">
          What you can do
        </h2>
        <p className="text-sm text-hawk-700">
          Available mobile workflows depend on your role. Use the drawer to
          navigate. To manage volunteers, account passwords, or roles, sign in
          on a desktop and visit Settings → User Management.
        </p>
      </section>

      <button
        type="button"
        onClick={handleLogout}
        style={{ minHeight: 'var(--mobile-touch-min, 56px)' }}
        className="w-full rounded-2xl border border-red-200 bg-white px-4 py-3 text-base font-semibold text-red-700 shadow-sm transition-colors hover:bg-red-50 focus:outline-none focus:ring-2 focus:ring-red-300"
      >
        Sign out
      </button>
    </div>
  );
}

export default MobileAccountPage;

